window.__QUIZ_DATA__=[{"id":"theory>Geography>2007>1>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1 : 50,000 and answer this question    On the map, mark and name one example of each of the following features with the letters in bracket:  (i) Spur (SP)  (ii) Gentle slope (OS)  (iii) Watershed (WS)  (iv) V-shaped valley (VS)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2007>1>b>i","subject":"Geography","year":"2007","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1 : 50,000 and answer this question    In your answer booklet, calculate the length (in km) of River Dakorobi from its source to the point where it joins River Sencha. (Show all workings clearly);","images":["data:image/png;base64,"],"marking_scheme":"Length of the river on the map = 10.8 (\u00b1 0.2cm)  1cm on the map represents 50,000 cm on ground. Scale of the map = (1 : 50,000)  Actual length of the river in km  =50,000 \u00d7 10.8100,000 = 5.4km ( + 0.1 km)","marks":"5","difficulty":"3"},{"id":"theory>Geography>2007>1>b>ii","subject":"Geography","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Study the map extract on a scale of 1 : 50,000 and answer this question  In your answer booklet, describe the relief of the mapped area.","images":["data:image/png;base64,"],"marking_scheme":"Description of Relief  - Height ranges from 950ft to over 3000ft  - NW is made up of rugged relief and sleep slopes.  - Generally, a highland area.  - Lowest in the NE and highest in the NW.  - Pockets of isolated hills cut acros from NW to SE.  - Other parts have gentle rolling slopes (SW and NE parts)","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>1>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Highlight the influence of relief on settlement in the area.","images":[],"marking_scheme":"- Passes attract settlement location e.g karlahi  - Settlements avoid the steep slopes  - The only settlements in the North-West are Mayo Dongi and Kenchungu  - The area mapped shows dispersed settlement pattern due to high relief of the area.  - The more rugged (mountainous) areas, north west of the map. Attract less settlements.  - Most settlements are located on the more gentle slopes south of the Map.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>2>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"The Table 1 below shows the volume of air passenger traffic between Lagos and four other cities in Nigeria in 1985. Study the table and use the data in it to answer this question that follow:  S/NRouteNo. of Passengers1  2  3  4Lagos - Abuja  Lagos - Enugu  Lagos - Port Harcourt  Lagos - Sokoto500,000  200,000  400,000  300,000  Table 1 - Volume of air passenger traffic between Lagos and four other cities in Nigeria, 1985.      Using the map of Nigeria above - Map B, construct a flow map/chart to represent the data in Table 1.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Flow Map/Chart    TITLE: Volume of air passener traffic flow between Lagos and four other cities in Nigeria, 1985.    Scale: 1mm to 50,000 passengers  Lagos - Abuja will be represented by   500,00050,000=10mm  Lagos - Enugu will be represented by  200,00050,000=4mm  Lagos - Port Harcourt will be represented by  400,00050,000=8mm  Lagos - Sokoto will be represented by  300,00050,000=6mm","marks":"12","difficulty":"3"},{"id":"theory>Geography>2007>2>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"State two advantages of representing data with flow maps.","images":[],"marking_scheme":"- Easy to compare from the thickness of the bands.  - Factual information may also be written on the flow line or along side it.  - The size of the bands or number of lines gives impression of the volume of traffic  - They give vivid impression of the traffic flow between two stations.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2007>3>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write a geographical account of Hot Desert Climate under the following    Location","images":[],"marking_scheme":"Location  - Found within Latitudes 15\u00b0 - 30\u00b0 North and South of the Equator.  - Mostly on western side of the continents.  - South America (Atalama desert)  - Arabia (Arabian desert)","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>3>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write a geographical account of Hot Desert Climate under the following   Characteristic features.","images":[],"marking_scheme":"- Sandy, rocky or story.  - Rainfall usually sudden and violent.  - Annual range of temperature is about 11\u00b0C  - Aridity or rainlessness  - High temperature of about 50\u00b0 - 77\u00b0  - Variable trade winds, hot in summer and cold in water.  - Clear skies conventional type.  - Affected by cold currents e.g canary cold current affecting sahara desert.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>3>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Write a geographical account of Hot Desert Climate under the following   Vegetation.","images":[],"marking_scheme":"- Small, waxy, leathery, hairy/needle leaves to reduce transpirations  - Sparse and scanty vegetation  - Examples are grasses, scrubs and herbs  - Some plants thick succulent stems is used to conserve water  - Examples of plants are acacia, date palm, cactus  - Most plants are drought resistant (xerophytes).","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>3>d","subject":"Geography","year":"2007","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Write a geographical account of Hot Desert Climate under the following   Human activities","images":[],"marking_scheme":"- Trading  - Mining   - Pastoral farming  - Food gathering, especially of fruits and nuts.  - Hunting for wild animals  - Crop cultivation particularly of grains with irrigation e.g millet, sorghum.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>4>a>i","subject":"Geography","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Define the term Environmental Resources.","images":[],"marking_scheme":"Environmental resources means any useful item in the environment or materials and substances that are useful for man.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2007>4>a>ii","subject":"Geography","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"List two types of Environmental Resources other than water.","images":[],"marking_scheme":"- Vegetation  - Atmospheric - Wind, sunshine, gases  - Human  - Mineral  - Land","marks":"4","difficulty":"1"},{"id":"theory>Geography>2007>4>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Highlight four ways in which water is important as an environmental resource.","images":[],"marking_scheme":"- Fishing   - Tourism  - Irrigation in agriculture  - Minerals  - Transportation  - Climate modification  - Domestic use","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>4>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Outline two problems that might arise from the degradation of water resources.","images":[],"marking_scheme":"- High cost of water treatment  - Water poisoning  - Destruction of aquatic life  - Inadequate fresh and pure water for domestic purposes  - Unemployment among fishermen","marks":"4","difficulty":"2"},{"id":"theory>Geography>2007>5>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Draw a diagram to show the relief features of an ocean floor.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2007>5>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Highlight three main characteristics of the continental shelf.","images":[],"marking_scheme":"- Sunlight able to penetrate  - Less than 250m deep  - Rich in plankton  - Areas of shallow water  - Contains minerals","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>5>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"In what three ways is the continental shelf of importance to man?","images":[],"marking_scheme":"- Tourist attraction  - Richest fishing grounds  - Continental shelf contains plankton which are rich fish food  - Recreational centres  - Contain some minerals such as petroleum","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>6>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Outline the characteristics of sedimentary rocks.","images":[],"marking_scheme":"- They are permeable.  - They are non-crystalline  - Sedimentary rocks are stratified/show district layers or strata.  - They are usually soft.  - Non-resistant to erosion  - They are fossilized rocks/they contains fossil of plants and animals.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2007>6>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe two ways in which sedimentary rocks can be formed.","images":[],"marking_scheme":"1. Mechanical formation of sedimentary rocks  - They may form conglomerates  - The deposited materials are pressed together to become solid by the weight of overlying deposits  - These are derived from sediments of pre-existing rocks  - This process of solidification is called Compaction or cementation    2. Organic formation of sedimentary rocks  - Remains of animals like corals or shellfish form calcareous rocks  - Examples are limestone, chalk etc  - These are formed from the remains of living organisms (plants or animals).    3. Chemical formation of sedimentary rocks  - These are rocks formed from precipitation  - They also formed from crystallization  - They are often refers to as evaporation  - Examples include potash, gypsum e.t.c","marks":"10","difficulty":"2"},{"id":"theory>Geography>2007>7>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is a plateau?","images":[],"marking_scheme":"A plateaux is an elevated upland with extensive level surface and often descending steeply to the surrounding lowland.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2007>7>b>i","subject":"Geography","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Describe the mode of formation of Tectonic plateaux.","images":[],"marking_scheme":"- Formed by earth movements  - Farily uniform altitude  - Some plateaux can result from fault blocks  - Example is Jos plateau.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>7>b>ii","subject":"Geography","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Describe the mode of formation of dissected plateaux.","images":[],"marking_scheme":"- They originate from either tectonic or volcanic plateaux  - Their surfaces are made irregular  - They are caused by running water, ice and winds  - Such plateaux are known as dissected plateaux.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2007>7>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Outline three ways in which plateaux are important to man.","images":[],"marking_scheme":"- Provision of good farmland.  - It provides sites for tourist attraction.  - Plateaux are rich in mineral resources.  - They promote cool climate.  - Site for generation of Hydro-Electric power.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2007>8>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Highlight four differences between the Tropical Grassland and the Temperate Grassland.","images":[],"marking_scheme":"- In West Africa, Tropical grasslands are known as savannah. In South Africa, they are known as Lianos, Campos in Brazil whereas the Temperate grasslands are known as stepper in Asia, Prairies in North America, Veldt in South Africa, Pampar in Argentina and the Downs in Austrialia.    - In the Tropical Grassland, the popular trees are Acacia, baobab, shea butter while the temperates grassland trees are poplar, willows and alders.    - The grasses of the temperate grasslands are more nutritious to animals than those of the tropical grassland.    - Trees of the Tropical grasslands are about 10 - 20m or more, they are tall and scattered while in temperate grasslands they are shorter.    - Grasses in the Tropical grasslands are more compact while that of Temperate grasslands are generally sparse and often in discontinuous clumps.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2007>8>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe the climate associated with one of the vegetation belts in 8(a) above.","images":[],"marking_scheme":"The Tropical Grassland  - It has two distinct seasons of wet and dry.  - There is abundant sunshine throughout the year.  - Rainfall is between 500mm and 1500m  - Rainfall is mainly convectional and it falls in wet season.  - Relative humidity is high during the rainy season (60%)  - Single maximum rainfall.    Temperate Grasslands  - It has four seasons, namely summer, autumn, winter and springs.  - The areas are influenced by South westerlies  - It has a high range of temperature  - The climate is continental  - Temperatures are high in summer, usually more than 25\u00b0C and cold in winter, to the freezing point  - Rainfall is convectional.  - Humidity is very high during summer.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2007>9>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Explain four ways in which water transport is important in international trade.","images":[],"marking_scheme":"- The maintenance cost of the harbour is relatively low, making it an advantage.  - It has a characteristic of transporting a wide variety of goods.  - Natural route are present, so little or no cost on constructions except on the harbour.  - It covers long distances which makes it easier to link all continents for trade purposes.  - It aids the carriage of bulky goods.  - It is available for all nations to use.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>9>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Outline four limitations of water transportation.","images":[],"marking_scheme":"- Ports may be frozen or even silted.  - Waterfalls or cataracts or rapids  - Some rivers has seasons  - High cost of dredging of ports  - Costs of acquiring ships is high  - Some dangerous aquatic animals can be present in the water  - Passengers on board experience sea sickness.  - Slow for perishable goods.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>9>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Suggest solutions to any two of the problems outlined in (b).","images":[],"marking_scheme":"- Use of ice-breakers  - Improved technology and installation of navigational aids.  - Educating about the rivers and their seasons by experts   - Loans should be granted for construction and of maintenance of ports as well as for acquiring ships.  - Installation of protective devices against dangerous water animals.  - Construction of fast moving ships.  - Improved technology such as construction of refrigerated vessels compartments for perishable goods.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2007>10>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain four factors which are responsible for the sparse population of the West Coast of South Africa.","images":[],"marking_scheme":"- Instability in political activities.  - Unfavourable climate conditions - Temperatures of desert type ranging 21\u00b0C to 40\u00b0C.  - Pests and disease outbreak.  - Poor development of mineral resources.  - Rivers are few which doesn't promote irrigation.  - The area falls in the rain shadow areas of Drakenberg mountain.  - Poor soil hinders farming activities resulting to low population growth  - Cold Benguela current leading to low precipitation.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>10>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight three disadvantages of the low population density of the West Coast of South Africa.","images":[],"marking_scheme":"- Low revenue to government  - Food shortage  - Low production output  - Unused facilities deteriorate  - Level of investment/industrialization will be low   - Low standard of living as a result of low income.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>10>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Suggest three ways by which the population in the West Coast of South Africa can be increased.","images":[],"marking_scheme":"- Government should promote agricultural activities  - Creation of job opportunities  - Use of fertilizers to increase soil nutrients  - Provision of infrastructure  - Improved transportation  - Provision of social amenities","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>11>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe four factors that favour the location of brewery industry.","images":[],"marking_scheme":"- Government policy  - Availability of raw materials  - Availability of labour   - Availability of technical know-how  - Constant/regular power supply  - Adequate transport facilities","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>11>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline three contributions of manufacturing industries to the economic development of Tropical Africa.","images":[],"marking_scheme":"- Development in infrastructure  - Transfer of technology  - Provision of goods and services  - Development of manpower  - International trade will be encouraged  - Provision of employment opportunities  - Other sectors of the economy will be stimulated.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>11>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight three problems facing manufacturing industries in Tropical Africa.","images":[],"marking_scheme":"- High cost of spare parts.  - Instability in political activities.  - Low level of entrepreneurship.  - Corruption at a higher rate in workers.  - Poor transportation network.  - Competition for foreign goods.  - Inadequate power supply.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>12>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria.   On the map, locate and name   (i) one area of cocoa production.  (ii) one area of cotton production  (iii) one area of rubber production  (iv) one towin in each of the areas in (a)(i) - (iii)","images":["data:image/png;base64,"],"marking_scheme":"(i) Cocoa: Ondo state, oyo state, ogun state, cross river, edo state, ekiti state e.t.c.    (ii) Cotton: Oyo state, Bauchi, Zamfara, Bornu state, Niger state, Plateau e.t.c    (iii) Rubber: Ogun, Ondo, Rain forest region of Nigeria, Ekiti state, Anambra state.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2007>12>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three physical conditions necessary for the production of any of the named crops in (a)(i) - (iii)","images":[],"marking_scheme":"Cocoa:  - Low annual, range of temperature less than 10\u00b0.  - Non-acidic soil.  - High temperature of about 27\u00b0C for growth and ripening.  - Moderate rainfall between 125cm to 200cm - January to October  - A dry period between December and February for drying the beans.    Cotton:  - Well-drained soil/undulating land.  - Moderate rainfall between 60cm and 125cm  - Dry sunny period for ripening of the bolls.  - High temperature of about 27\u00b0C for growth, ripening and harvesting, rich clayey loamy soil.    Rubber:  - Humus soil  - Moderate temperature of about 27\u00b0C  - Abundance of sunshine  - Deep soil  - Evenly distribution of rainfall.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>12>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline any two ways in which cash crops are important to the economy of Nigeria.","images":[],"marking_scheme":"- Source of income to farmers  - Raw materials for industries  - Development of infrastructure  - Source of employment  - Source of revenue to government  - Market for farm inputs e.g Herbicides, pesticides, fertilizers e.t.c.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>13>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria.  On the map, show and name   (i) three vegetation belts  (ii) one important town in each belt.","images":[],"marking_scheme":"*#img5.png**#  i. Vegetation belts at = e.g Mangrove swamps.  ii. High forest, Guinea Savanna, Sudan savanna, Sahel savanna.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2007>13>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Highlight three effects of rainfall, on vegetation in Nigeria.","images":[],"marking_scheme":"- Low rainfall gives rise to the growth of short deciduous trees in the north, scanty rainfall in the extreme north gives rise to short scattered grasses scanty or no rainfall in the extreme north-east give rise to scrub land.    - High rainfall gives rise to evergreen forest in the South.    - Heavy rainfall supports the growth of tall trees in the south.     - Low rainfall gives rise to the growth of grasses in the north.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>13>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"State two uses of vegetation resources in Nigeria.","images":[],"marking_scheme":"- Provision of raw materials for industries.  - Leaves and grasses are used for roofing, timber for construction purpose.  - It provides site for tourism.  - The roots, barks and leaves are used as medicinal herbs.  - Sources of food - fruits and nuts, game wood used as source of fuel.  - Employment for hunters, lumbermen forest officer e.t.c","marks":"4","difficulty":"1"},{"id":"theory>Geography>2007>14>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw sketch map of Nigeria. On the map, show and name  (i) one highland area in the North East   (ii) one highland area in the West  (iii) two rivers that take their sources from these highland areas;  (iv) one man-made lake  (v) the lake Chad.","images":["data:image/png;base64,"],"marking_scheme":"(i) One highland area in the North East e.g Biu Plateau and mandara mts.  (ii) One highland area in the West e.g Western upland  (iii) 2 rivers at (NE: Ngoda, Yedseram, Hawai) (West: Ogun, Osun, Osse, Moshi, Awum)  (iv) One man-made lake e.g kainji lake, shiroro lake, jebba lake.  (v) The Lake Chad","marks":"12","difficulty":"3"},{"id":"theory>Geography>2007>14>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Explain four ways in which highland of Nigeria are important.","images":[],"marking_scheme":"- Important for transhumance  - Tourist attraction  - A site or sites for settlement  - Sources of many rivers  - Sources of mineral resources  - Sites for the erection of communication masts.  - For the growth of special crops e.g tea, apple in Mambila plateau.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>15>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Explain three conditions that favour fruit farming in the Mediterranean Regions of Africa.","images":[],"marking_scheme":"- Temperature range of 25\u00b0C - 27\u00b0C  - Availability of rivers for irrigation  - Use of advanced methods of cultivation e.g terracing   - Undulating relief with good drainage  - Good transport network  - Winter rainfall of 25 - 75cm for planting and growth.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>15>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Outline four problems facing fruit farming in the Mediterranean Regions of Africa.","images":[],"marking_scheme":"- Some places have poor soil.  - Disease outbreak.  - Over production/glut   - Soil erosion mostly along steep hillsides  - Pests  - Inadequate trained personnel.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>15>c","subject":"Geography","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highland three ways in which fruit farming is of economic importance to the Mediterranean Regions.","images":[],"marking_scheme":"- Source of revenue to government  - Specialization in viticulture  - Provision of food for man  - Town growth  - Provision of employment  - Development in infrastructure  - Vinegard owners earn income","marks":"6","difficulty":"2"},{"id":"theory>Geography>2007>16>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw a sketch map of the Nile Valley.  On the map, show and name  (i) two farming areas  (ii) two products from each area in (a)(i) above.","images":["data:image/png;base64,"],"marking_scheme":"(i) Areas: Nile Delta, Gezira scheme, Nile valley  (ii) Products: Rice, cotton, maize, sugar cane, wheat, barley groundnut, millet e.t.c.","marks":"12","difficulty":"3"},{"id":"theory>Geography>2007>16>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"In what five ways is the River Nile of economic importance to Egypt and the Sudan?","images":[],"marking_scheme":"- For domestic use  - It is use industrially  - It provides employment for fisherman  - Rich minerals in valley e.g petroleum, phosphate, maganese e.t.c  - As a means of transportation  - Tourist attraction - Holiday Resort  - The river provides alluvial soil for farming.  - Source of water for irrigation","marks":"8","difficulty":"2"},{"id":"theory>Geography>2007>17>a","subject":"Geography","year":"2007","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw a sketch map of Africa.  On the map, locate and name   (i) Rivers Niger and Zambezi  (ii) Lake Victoria  (iii) Latitudes 23 1/2\u00b0N and 23 1/2\u00b0S;  (iv) The Atlass Mountains   (v) Two mining areas - one for petroleum in West Africa and one for gold in South Africa.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2007>17>b","subject":"Geography","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight five ways in which either petroleum or gold is of economic importance to the area in (a)(v).","images":[],"marking_scheme":"1. Petroleum (West Africa)  - It improves standard of living.  - Development of settlements.  - Raw materials for industries  - It attracts foreign investors.  - Foreign exchange earnings.  - Transfer of technology  - Development of infrastructure  - Source of income  - Source of energy.    2. Gold (South Africa)  - Source of income.  - Development of infrastructure  - Employment  - Foreign exchange earnings  - Raw materials for industries  - It attracts foreign investors  - Production of jewelries e.g ear rings, necklaces, trinkets e.t.c.","marks":"10","difficulty":"2"}];